cadishfile:
example.com {
    @html   content_type text/html
    @assets path /assets/*
    edge {
        worker  cadish-edge-example
        kv      EDGE_CACHE
        default local
        distribute @html
        skip @assets
    }
    cache_key url
    cache_ttl default ttl 30s grace 10m
    header +cache_status X-Cache
}
